#include <omp.h>
#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <stdbool.h>

#ifdef __cplusplus
extern "C" {
#endif

#include "../common.h"
#include "../util/timer/timer.h"

typedef struct record {
	int value;
} record;

typedef struct knode {
	int location;
	int indices [508 + 1];
	int  keys [508 + 1];
	bool is_leaf;
	int num_keys;
} knode;

static void findK_parallel(	long height,
							knode *knodes,
							long knodes_elem,
							record *records,
							long *currKnode,
							long *offset,
							int *keys,
							record *ans,
							int count,
							int threadsPerBlock)
{
	#pragma omp parallel num_threads(count)
	{
		int bid = omp_get_thread_num();
		int thid;
		long current_knode;
		long current_offset;
		int key_val;

		current_knode = currKnode[bid];
		current_offset = offset[bid];
		key_val = keys[bid];

		for(int i = 0; i < height; i++){

			for(thid = 0; thid < threadsPerBlock; thid++){
				if(thid < knodes[current_knode].num_keys + 1) {
					int k_current = knodes[current_knode].keys[thid];
					int k_next = (thid + 1 < knodes[current_knode].num_keys + 1) ? knodes[current_knode].keys[thid+1] : 2147483647; 

					if(k_current <= key_val && k_next > key_val){
						if(knodes[current_offset].indices[thid] < knodes_elem){
							current_offset = knodes[current_offset].indices[thid];
						}
					}
				}
			}

			current_knode = current_offset;
		}


		for(thid = 0; thid < threadsPerBlock; thid++){
			if(thid < knodes[current_knode].num_keys + 1) {
				if(knodes[current_knode].keys[thid] == key_val){
					ans[bid].value = records[knodes[current_knode].indices[thid]].value;
					break;
				}
			}
		}

		currKnode[bid] = current_knode;
		offset[bid] = current_offset;
	}
}

void 
kernel_gpu_cuda_wrapper(record *records,
						long records_mem,
						knode *knodes,
						long knodes_elem,
						long knodes_mem,

						int order,
						long maxheight,
						int count,

						long *currKnode,
						long *offset,
						int *keys,
						record *ans)
{
	long long time0;
	long long time1;
	long long time2;
	long long time3;
	long long time4;
	long long time5;
	long long time6;

	time0 = get_time();

	time1 = get_time();

	int threadsPerBlock;
	threadsPerBlock = order < 1024 ? order : 1024;

	printf("# of blocks = %d, # of threads/block = %d (ensure that device can handle)\n", count, threadsPerBlock);

	time2 = get_time();

	time3 = get_time();

	findK_parallel(	maxheight,
					knodes,
					knodes_elem,
					records,
					currKnode,
					offset,
					keys,
					ans,
					count,
					threadsPerBlock);

	time4 = get_time();

	time5 = get_time();

	time6 = get_time();

	printf("Time spent in different stages of GPU_CUDA KERNEL:\n");

	printf("%15.12f s, %15.12f % : GPU: SET DEVICE / DRIVER INIT\n",	(float) (time1-time0) / 1000000, (float) (time1-time0) / (float) (time6-time0) * 100);
	printf("%15.12f s, %15.12f % : GPU MEM: ALO\n", 					(float) (time2-time1) / 1000000, (float) (time2-time1) / (float) (time6-time0) * 100);
	printf("%15.12f s, %15.12f % : GPU MEM: COPY IN\n",					(float) (time3-time2) / 1000000, (float) (time3-time2) / (float) (time6-time0) * 100);

	printf("%15.12f s, %15.12f % : GPU: KERNEL\n",						(float) (time4-time3) / 1000000, (float) (time4-time3) / (float) (time6-time0) * 100);

	printf("%15.12f s, %15.12f % : GPU MEM: COPY OUT\n",				(float) (time5-time4) / 1000000, (float) (time5-time4) / (float) (time6-time0) * 100);
	printf("%15.12f s, %15.12f % : GPU MEM: FRE\n", 					(float) (time6-time5) / 1000000, (float) (time6-time5) / (float) (time6-time0) * 100);

	printf("Total time:\n");
	printf("%.12f s\n", 												(float) (time6-time0) / 1000000);
}

#ifdef __cplusplus
}
#endif

