static void findRangeK_parallel(	long height,
									knode *knodes,
									long knodes_elem,
									long *currKnode,
									long *offset,
									long *lastKnode,
									long *offset_2,
									int *start,
									int *end,
									int *recstart,
									int *reclength,
									int count,
									int threadsPerBlock)
{
	#pragma omp parallel num_threads(count)
	{
		int bid = omp_get_thread_num();
		int thid;
		long current_knode;
		long current_last_knode;
		long current_offset;
		long current_offset_2;
		int start_val;
		int end_val;
		int rec_start_val = -1;
		int rec_len_val = -1;

		current_knode = currKnode[bid];
		current_last_knode = lastKnode[bid];
		current_offset = offset[bid];
		current_offset_2 = offset_2[bid];
		start_val = start[bid];
		end_val = end[bid];

		for(int i = 0; i < height; i++){

			for(thid = 0; thid < threadsPerBlock; thid++){
				if(thid < knodes[current_knode].num_keys + 1) {
					int k_current = knodes[current_knode].keys[thid];
					int k_next = (thid + 1 < knodes[current_knode].num_keys + 1) ? knodes[current_knode].keys[thid+1] : 2147483647;

					if(k_current <= start_val && k_next > start_val){
						if(knodes[current_knode].indices[thid] < knodes_elem){
							current_offset = knodes[current_knode].indices[thid];
						}
					}
				}

				if(thid < knodes[current_last_knode].num_keys + 1) {
					int k_current = knodes[current_last_knode].keys[thid];
					int k_next = (thid + 1 < knodes[current_last_knode].num_keys + 1) ? knodes[current_last_knode].keys[thid+1] : 2147483647;

					if(k_current <= end_val && k_next > end_val){
						if(knodes[current_last_knode].indices[thid] < knodes_elem){
							current_offset_2 = knodes[current_last_knode].indices[thid];
						}
					}
				}
			}

			current_knode = current_offset;
			current_last_knode = current_offset_2;
		}


		for(thid = 0; thid < threadsPerBlock; thid++){
			if(thid < knodes[current_knode].num_keys + 1) {
				if(knodes[current_knode].keys[thid] == start_val){
					rec_start_val = knodes[current_knode].indices[thid];
					break;
				}
			}
		}

		for(thid = 0; thid < threadsPerBlock; thid++){
			if(thid < knodes[current_last_knode].num_keys + 1) {
				if(knodes[current_last_knode].keys[thid] == end_val){
					rec_len_val = knodes[current_last_knode].indices[thid] - rec_start_val + 1;
					break;
				}
			}
		}

		currKnode[bid] = current_knode;
		lastKnode[bid] = current_last_knode;
		offset[bid] = current_offset;
		offset_2[bid] = current_offset_2;
		recstart[bid] = rec_start_val;
		reclength[bid] = rec_len_val;
	}
}

